function toggleContrast(e){document.getElementById("checkSwitch").checked?document.body.classList.add(e):document.body.classList.remove(e)}function setContrast(){let e=document.getElementById("checkSwitch").checked;localStorage.setItem("status_contrast",e)}function getContrast(){let e=localStorage.getItem("status_contrast");"true"===e?(document.getElementById("checkSwitch").checked=!0,document.body.classList.add("dark")):"false"===e?(document.getElementById("checkSwitch").checked=!1,document.body.classList.remove("dark")):setContrast()}function handleClickFocus(e){e.preventDefault();const t=this.getAttribute("href"),n=document.querySelector(t);n&&(n.tabIndex=-1,n.focus(),n.removeAttribute("tabindex"))}function ocultarIconosInaccesibles(){let e=document.querySelectorAll('.mb2mm-arrow, [class^="fab fa-"]');0!==e.length?e.forEach(function(e){e.setAttribute("aria-hidden","true")}):console.warn("No se encontraron iconos para ocultar.")}function agregarSpanEnlacesExternos(){let e=document.querySelectorAll(".link-new-window");0!==e.length?e.forEach(function(e){let t=document.createElement("span");t.textContent="(Abre en una nueva ventana)",t.classList.add("sr-only"),e.appendChild(t)}):console.warn('No se encontraron enlaces con la clase .link-new-window".')}function syncToggleWithBodyClass(){const e=document.getElementById("checkSwitch");if(!e)return;new MutationObserver(function(t){t.forEach(function(t){if("class"===t.attributeName){const t=document.body.classList.contains("dark");e.checked!==t&&(e.checked=t,localStorage.setItem("status_contrast",t))}})}).observe(document.body,{attributes:!0})}document.addEventListener("DOMContentLoaded",()=>{document.getElementById("checkSwitch").addEventListener("click",setContrast),getContrast(),syncToggleWithBodyClass(),ocultarIconosInaccesibles(),agregarSpanEnlacesExternos();document.querySelectorAll(".navbar-nav .nav-link").forEach(e=>{e.addEventListener("click",handleClickFocus)})});